"""Generate 30-question Physics quizzes for Unit 3: Forces & Newton's Laws (8 lessons)."""
import json, os

def make_quiz(unit, lesson, title, questions, base_dir="content_data/PhysicsLessons"):
    quiz_questions = []
    for i, q in enumerate(questions):
        q_text, correct, w1, w2, w3, explanation = q
        quiz_questions.append({
            "question_number": i + 1,
            "question_text": q_text,
            "attempted": 2,
            "data_i18n": None,
            "options": [
                {"text": correct, "is_correct": True, "data_i18n": None},
                {"text": w1, "is_correct": False, "data_i18n": None},
                {"text": w2, "is_correct": False, "data_i18n": None},
                {"text": w3, "is_correct": False, "data_i18n": None},
            ],
            "explanation": explanation
        })
    data = {"unit": int(unit), "lesson_number": lesson, "title": title, "course": "Physics", "quiz_questions": quiz_questions}
    path = os.path.join(base_dir, f"Unit{unit}", f"Lesson{lesson}_Quiz.json")
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    print(f"  Written: {path} ({len(questions)} questions)")

